+import Fastify from 'fastify';
+import cors from '@fastify/cors';
+import helmet from '@fastify/helmet';
+import multipart from '@fastify/multipart';
+import { createBullBoard } from '@bull-board/api';
+import { BullMQAdapter } from '@bull-board/api/bullMQAdapter';
+import { FastifyAdapter } from '@bull-board/fastify';
+import { serializerCompiler, validatorCompiler, type ZodTypeProvider } from 'fastify-type-provider-zod';
+
+import { authorize } from '@/shared/middleware/authorize';
+import { authenticate } from '@/shared/middleware/authenticate';
+import { registerErrorHandler } from '@/shared/errors/error-handler';
+import { logger } from '@/shared/utils/logger';
+import { cgpaQueue, emailQueue, ingestionQueue, ocrQueue, rankingQueue } from '@/shared/queue/queues';
+
+import { authModule } from '@/modules/auth';
+import { profileModule } from '@/modules/profile';
+import { onboardingModule } from '@/modules/onboarding';
+import { ingestionModule } from '@/modules/ingestion';
+import { rankingModule } from '@/modules/ranking';
+import { adminModule } from '@/modules/admin';
+
+// TODO: implement
+
+export function buildApp() {
+  const app = Fastify({ logger });
+  const typed = app.withTypeProvider<ZodTypeProvider>();
+
+  typed.setValidatorCompiler(validatorCompiler);
+  typed.setSerializerCompiler(serializerCompiler);
+
+  void typed.register(cors, { origin: true });
+  void typed.register(helmet);
+  void typed.register(multipart);
+
+  registerErrorHandler(typed);
+
+  typed.get('/health', async () => ({
+    status: 'ok',
+    timestamp: new Date().toISOString()
+  }));
+
+  const serverAdapter = new FastifyAdapter();
+  serverAdapter.setBasePath('/admin/queues');
+  createBullBoard({
+    serverAdapter,
+    queues: [
+      new BullMQAdapter(ingestionQueue),
+      new BullMQAdapter(rankingQueue),
+      new BullMQAdapter(cgpaQueue),
+      new BullMQAdapter(emailQueue),
+      new BullMQAdapter(ocrQueue)
+    ]
+  });
+
+  void typed.register(serverAdapter.registerPlugin(), {
+    prefix: '/admin/queues',
+    preHandler: [authenticate, authorize(['admin'])]
+  });
+
+  void typed.register(authModule, { prefix: '/auth' });
+  void typed.register(profileModule, { prefix: '/profile' });
+  void typed.register(onboardingModule, { prefix: '/onboarding' });
+  void typed.register(ingestionModule, { prefix: '/ingestion' });
+  void typed.register(rankingModule, { prefix: '/ranking' });
+  void typed.register(adminModule, { prefix: '/admin' });
+
+  return typed;
+}
+
